{"type": "email", "id": "email_001", "subject": "Q2 2025 Performance Analysis Results", "from": "john.doe@mediconnsolutions.com", "from_name": "John Doe", "to": ["emily.chen@mediconnsolutions.com", "sarah.jones@mediconnsolutions.com"], "cc": ["michael.brown@mediconnsolutions.com", "lucy.taylor@mediconnsolutions.com", "mark.wilson@mediconnsolutions.com", "rachel.thomas@mediconnsolutions.com"], "date": "2025-07-01 09:30:00", "body": "Hello team,

